import (
	"compress/gzip"
	"io"
)

func inflate(r io.Reader, dst io.Writer) error {
	gz, err := gzip.NewReader(r)
	if err != nil {
		return err
	}
	defer gz.Close()
	_, err = io.Copy(dst, gz)
	return err
}

